const body = $input.first().json;
const keywords = body.keywords || [];
return keywords.map(keyword => ({ json: { keyword } }));

const allItems = $input.all().map(i => i.json);

const flat = allItems.flatMap(item =>
  Array.isArray(item.allReels) ? item.allReels : [item]
);

const thirtyDaysAgo = new Date();
thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

const unique = Array.from(
  new Map(flat.map(r => [r.platform + '_' + r.code, r])).values()
);

const scored = unique
  .filter(r => r.views > 0)
  .filter(r => {
    if (r.platform === 'tiktok') {
      if (!r.date) return false;
      return new Date(r.date) >= thirtyDaysAgo;
    }
    return true;
  })
  .map(r => ({
    ...r,
    score: (r.views * 0.6) + ((r.shares || 0) * 0.4)
  }))
  .sort((a, b) => b.score - a.score)
  .slice(0, 100);

return scored.map((r, i) => ({
  json: { rank: i + 1, ...r }
}));

const items = $input.all().map(i => i.json);


return items
  .filter(v => v.playCount > 0)
  .map(v => ({
    json: {
      platform: 'tiktok',
      videoUrl: v.videoMeta?.subtitleLinks?.[0]?.downloadLink || '',
      code: v.id || v.webVideoUrl,
      keyword: $('Loop Over Items6').item.json.keyword,
      username: v.authorMeta?.name || v.author?.uniqueId || '',
      views: v.playCount || 0,
      likes: v.diggCount || 0,
      comments: v.commentCount || 0,
      shares: v.shareCount || 0,
      caption: (v.text || '').substring(0, 150),
      url: v.webVideoUrl || `https://www.tiktok.com/@${v.authorMeta?.name}/video/${v.id}`,
      date: v.createTimeISO || ''
    }
  }));

