const whisperResult = $input.first().json;
const item = $('Loop Over Items4').item.json;

// 1. Language filter — reject non-English
const detectedLang = whisperResult?.language || '';
if (detectedLang !== 'en' && detectedLang !== 'english') {
  return [{ json: { ...item, transcript: '', hook: null, hookSkipped: true, skipReason: 'not_english' } }];
}

const transcript = whisperResult?.text || '';

// 2. Too short = no real speech
const words = transcript.trim().split(/\s+/);
if (words.length < 15) {
  return [{ json: { ...item, transcript: '', hook: null, hookSkipped: true, skipReason: 'too_short' } }];
}

// 3. Use segment-level no_speech_prob to detect music/ambient
const segments = whisperResult?.segments || [];
if (segments.length > 0) {
  const avgNoSpeech = segments.reduce((sum, s) => sum + (s.no_speech_prob || 0), 0) / segments.length;
  const avgLogprob = segments.reduce((sum, s) => sum + (s.avg_logprob || 0), 0) / segments.length;

  // High no_speech_prob = audio is music/ambient, not voice
  if (avgNoSpeech > 0.4) {
    return [{ json: { ...item, transcript: '', hook: null, hookSkipped: true, skipReason: 'music_detected' } }];
  }

  // Very low logprob = Whisper is struggling to understand (likely not speech)
  if (avgLogprob < -1.2) {
    return [{ json: { ...item, transcript: '', hook: null, hookSkipped: true, skipReason: 'low_confidence' } }];
  }
}

// 4. Repetition check for songs that slip through
const wordFreq = {};
words.forEach(w => {
  const clean = w.toLowerCase().replace(/[^a-z]/g, '');
  if (clean.length > 3) wordFreq[clean] = (wordFreq[clean] || 0) + 1;
});
const maxFreq = Math.max(...Object.values(wordFreq), 0);
if (maxFreq / words.length > 0.15) {
  return [{ json: { ...item, transcript: '', hook: null, hookSkipped: true, skipReason: 'repetitive_lyrics' } }];
}

// Passed all filters — extract hook
const sentences = transcript.match(/[^.!?]+[.!?]+/g) || [transcript];
const hook = sentences.slice(0, 3).join(' ').trim() || null;

return [{ json: { ...item, transcript, hook, hookSkipped: false } }];

